#include<bits/stdc++.h>
using namespace std;
const int N = 4e5+5;
const long long INF = 0x3f3f3f3f3f3f3f3f;
struct node{long long x,y;}a[N],tmp[N];
int n;
bool cmp(node n1,node n2){return n1.x<n2.x;}
long long FZ(int l,int r){
	if(l==r)return INF;
	
	
	int mid=(l+r)/2;
	if(mid==r)mid--;
	long long midx=a[mid].x;
	long long d=min(FZ(l,mid),FZ(mid+1,r));
	
	
	int id_1=l,id_2=mid+1,cnt=l-1;
	while(id_1<=mid&&id_2<=r){
		if(a[id_1].y<a[id_2].y)tmp[++cnt]=a[id_1++];
		else tmp[++cnt]=a[id_2++];
	}
	while(id_1<=mid)tmp[++cnt]=a[id_1++];
	while(id_2<=r)tmp[++cnt]=a[id_2++];
	for(int i=l;i<=r;i++)a[i]=tmp[i];
	
	
	cnt=0;
	for(int i=l;i<=r;i++)
		if((a[i].x-midx)*(a[i].x-midx)<=d)tmp[++cnt]=a[i];
	for(int i=1;i<=cnt;i++){
		for(int j=i-1;j>=1&&((tmp[i].y-tmp[j].y)*(tmp[i].y-tmp[j].y)<=d);j--){
			d=min(d,(tmp[i].x-tmp[j].x)*(tmp[i].x-tmp[j].x)+(tmp[i].y-tmp[j].y)*(tmp[i].y-tmp[j].y));
		}
	}
	
	
	return d;
}
int main(){
	cin>>n;
	for(int i=1;i<=n;++i)cin>>a[i].x>>a[i].y;
	sort(a+1,a+n+1,cmp);
	cout<<FZ(1,n);
	return 0;
}
